class Box<T> {
    private T value;
    Box(T v)        { value = v; }
    Box()           { value = null; }
    T get()         { return value; }
    void set(T v)   { value = v; }
    boolean isEmpty() { return value == null; }
}
public class App {
    public static void main(String[] args) {
        Box<String> sb = new Box<>("hello");
        System.out.println("String box: " + sb.get() + " | empty: " + sb.isEmpty());
        sb.set(null);
        System.out.println("After clear: empty: " + sb.isEmpty());
        Box<Integer> ib = new Box<>(42);
        System.out.println("Int box: " + ib.get());
    }
}

class Pair<A, B> {
    private final A first;
    private final B second;
    Pair(A a, B b) { first=a; second=b; }
    A getFirst()  { return first; }
    B getSecond() { return second; }
    Pair<B, A> swap() { return new Pair<>(second, first); }
    public String toString() { return "(" + first + ", " + second + ")"; }
}
public class App {
    public static void main(String[] args) {
        Pair<String, Integer> p1 = new Pair<>("Hyderabad", 500032);
        System.out.println(p1);
        System.out.println("Swapped: " + p1.swap());
        Pair<String, Boolean> p2 = new Pair<>("premium", true);
        System.out.println(p2);
    }
}

import java.util.*;
class Stack<T> {
    private List<T> items = new ArrayList<>();
    void push(T item) { items.add(item); }
    T pop() {
        if (isEmpty()) throw new NoSuchElementException("Stack is empty");
        return items.remove(items.size() - 1);
    }
    T peek() {
        if (isEmpty()) throw new NoSuchElementException("Stack is empty");
        return items.get(items.size() - 1);
    }
    boolean isEmpty() { return items.isEmpty(); }
    int size()        { return items.size(); }
}
public class App {
    public static void main(String[] args) {
        Stack<Integer> stack = new Stack<>();
        stack.push(10); stack.push(20); stack.push(30);
        System.out.println("Size: " + stack.size() + ", peek: " + stack.peek());
        while (!stack.isEmpty()) System.out.println(stack.pop());
        System.out.println("Empty: " + stack.isEmpty());
    }
}

class TimedEntry<T> {
    private final T value;
    private final long createdAt;

    TimedEntry(T value) {
        this.value = value;
        this.createdAt = System.currentTimeMillis();
    }

    T getValue()     { return value; }
    long getAge()    { return System.currentTimeMillis() - createdAt; }
    boolean isExpired(long maxAgeMs) { return getAge() > maxAgeMs; }
}
public class App {
    public static void main(String[] args) throws InterruptedException {
        TimedEntry<String> entry = new TimedEntry<>("Aisha");
        System.out.println("Value: " + entry.getValue());
        System.out.println("Expired (0ms max): " + entry.isExpired(0));
        System.out.println("Expired (100000ms max): " + entry.isExpired(100000));
    }
}

