import java.util.*;
class Queue<T> {
    private LinkedList<T> items = new LinkedList<>();
    void enqueue(T item) { items.addLast(item); }
    T dequeue() {
        if (isEmpty()) throw new NoSuchElementException("Queue is empty");
        return items.removeFirst();
    }
    T peek() {
        if (isEmpty()) throw new NoSuchElementException("Queue is empty");
        return items.getFirst();
    }
    boolean isEmpty() { return items.isEmpty(); }
    int size()        { return items.size(); }
}
public class App {
    public static void main(String[] args) {
        Queue<String> queue = new Queue<>();
        queue.enqueue("Aisha");
        queue.enqueue("Raj");
        queue.enqueue("Priya");
        System.out.println("Size: " + queue.size() + ", front: " + queue.peek());
        while (!queue.isEmpty()) System.out.println(queue.dequeue());
        System.out.println("Empty: " + queue.isEmpty());
    }
}

exercises.instructions:
Create `ApiResponse<T>` with: status (int), message (String), data (T). Factory methods: ok(T data), error(int status, String message). toString formats as JSON-like string.

Expected output:
{"status":200,"message":"OK","data":"Aisha"}
{"status":404,"message":"User not found","data":null}

exercises.expected_solution:
class ApiResponse<T> {
    private final int status;
    private final String message;
    private final T data;

    private ApiResponse(int status, String message, T data) {
        this.status = status; this.message = message; this.data = data;
    }

    static <T> ApiResponse<T> ok(T data) {
        return new ApiResponse<>(200, "OK", data);
    }

    static <T> ApiResponse<T> error(int status, String message) {
        return new ApiResponse<>(status, message, null);
    }

    int getStatus()   { return status; }
    String getMessage() { return message; }
    T getData()       { return data; }

    public String toString() {
        return "{\"status\":" + status + ",\"message\":\"" + message + "\",\"data\":"
            + (data == null ? "null" : "\"" + data + "\"") + "}";
    }
}
public class App {
    public static void main(String[] args) {
        System.out.println(ApiResponse.ok("Aisha"));
        System.out.println(ApiResponse.error(404, "User not found"));
    }
}

import java.util.function.*;
class Wrapper<T> {
    private final T value;
    Wrapper(T v)          { value = v; }
    T get()               { return value; }
    boolean hasValue()    { return value != null; }
    T orElse(T def)       { return hasValue() ? value : def; }

    <R> Wrapper<R> map(Function<T, R> fn) {
        if (!hasValue()) return new Wrapper<>(null);
        return new Wrapper<>(fn.apply(value));
    }

    public String toString() { return "Wrapper(" + value + ")"; }
}
public class App {
    public static void main(String[] args) {
        Wrapper<String> w = new Wrapper<>("hello");
        System.out.println(w);

        Wrapper<Integer> len = w.map(String::length);
        System.out.println(len);

        Wrapper<String> formatted = len.map(n -> "length=" + n);
        System.out.println(formatted);

        Wrapper<String> empty = new Wrapper<>(null);
        System.out.println("null wrapper: " + empty.orElse("no value"));
    }
}

class KeyValue<K, V> {
