        KeyValue<Integer, String> kv2 = new KeyValue<>(1, "first");
        System.out.println("rank=" + kv2.getValue());
    }
}

import java.util.function.*;
class Result<T> {
    private final T value;
    private final String error;
    private final boolean ok;
    private Result(T v, String e, boolean ok) { value=v; error=e; this.ok=ok; }

    static <T> Result<T> success(T v)    { return new Result<>(v, null, true); }
    static <T> Result<T> failure(String e) { return new Result<>(null, e, false); }

    boolean isSuccess() { return ok; }
    T getValue()    { return value; }
    String getError() { return error; }
    T orElse(T def) { return ok ? value : def; }

    <R> Result<R> map(Function<T, R> fn) {
        return ok ? Result.success(fn.apply(value)) : Result.failure(error);
    }

    public String toString() { return ok ? "Success(" + value + ")" : "Failure(" + error + ")"; }
}
public class App {
    static Result<Double> parseAmount(String s) {
        try { return Result.success(Double.parseDouble(s)); }
        catch (NumberFormatException e) { return Result.failure("Not a number: " + s); }
    }
    static Result<Double> requirePositive(double v) {
        return v > 0 ? Result.success(v) : Result.failure("Must be positive");
    }

    public static void main(String[] args) {
        Result<Double> r1 = parseAmount("5000").map(v -> v).map(Result::success).orElse(null) == null
            ? parseAmount("5000")
            : parseAmount("5000");
        // Simpler: just chain directly
        System.out.println(parseAmount("5000").map(v -> v));
        System.out.println(parseAmount("five-hundred"));
        System.out.println(parseAmount("-100").map(v -> requirePositive(v).isSuccess() ? v : null)
            .map(v -> v == null ? Result.<Double>failure("Must be positive").getValue() : v));
        // Actually just use direct chain:
        Result<Double> amount1 = parseAmount("5000");
        Result<Double> amount2 = parseAmount("-100");
        // For cleaner output, rebuild:
        System.out.println("Final: ₹" + amount1.orElse(0.0));
        System.out.println("Final on failure: ₹" + parseAmount("bad").orElse(0.0));
    }
}

import java.util.*;
class Page<T> {
    private final List<T> content;
    private final int pageNumber;
    private final int pageSize;
    private final long totalElements;

    Page(List<T> content, int pageNum, int pageSize, long totalElements) {
        this.content = new ArrayList<>(content);
        this.pageNumber = pageNum;
        this.pageSize = pageSize;
        this.totalElements = totalElements;
    }

    List<T> getContent()      { return Collections.unmodifiableList(content); }
    int getPageNumber()        { return pageNumber; }
    int getPageSize()          { return pageSize; }
    long getTotalElements()    { return totalElements; }
    int totalPages()           { return (int) Math.ceil((double) totalElements / pageSize); }
    boolean hasNext()          { return pageNumber < totalPages(); }
    boolean hasPrevious()      { return pageNumber > 1; }
    boolean isEmpty()          { return content.isEmpty(); }
    public String toString()   { return "Page " + pageNumber + "/" + totalPages() + " (" + totalElements + " total)"; }
}
public class App {
    public static void main(String[] args) {
        List<String> names = Arrays.asList("Priya", "Vikram", "Anita");
        Page<String> page = new Page<>(names, 2, 7, 25);
        System.out.println(page);
        System.out.println("Content: " + page.getContent());
        System.out.println("Has next: " + page.hasNext() + " | Has prev: " + page.hasPrevious());
    }
}

