import java.util.*;
import java.util.function.*;
class EventBus<E> {
    private final List<Consumer<E>> listeners = new ArrayList<>();
    void subscribe(Consumer<E> listener) { listeners.add(listener); }
    void publish(E event) { listeners.forEach(l -> l.accept(event)); }
    void unsubscribeAll() { listeners.clear(); }
    int subscriberCount() { return listeners.size(); }
}
class OrderEvent {
    String orderId; double amount;
    OrderEvent(String id, double amt) { orderId=id; amount=amt; }
}
public class App {
    public static void main(String[] args) {
        // String event bus
        System.out.println("String events:");
        EventBus<String> strBus = new EventBus<>();
        strBus.subscribe(e -> System.out.println("Listener1: " + e));
        strBus.subscribe(e -> System.out.println("Listener2: " + e));
        strBus.publish("Hello");
        strBus.publish("World");

        // Order event bus
        System.out.println("Order events:");
        EventBus<OrderEvent> orderBus = new EventBus<>();
        orderBus.subscribe(e -> System.out.println("Processing: " + e.orderId + " (₹" + e.amount + ")"));
        orderBus.subscribe(e -> System.out.println("Logging: " + e.orderId));
        orderBus.publish(new OrderEvent("ORD-001", 3500));
    }
}
